const { chromium } = require('playwright-core');
(async() => {
  const browser = await chromium.launch({headless: true, executablePath: '/usr/sbin/chromium'});
  const page = await browser.newPage({viewport: {width: 1400, height: 1000}, deviceScaleFactor: 1});
  const errors = [];
  page.on('console', msg => { if (msg.type()==='error') errors.push(msg.text()); });
  page.on('pageerror', err => errors.push('PAGEERROR: ' + err.message));
  await page.goto('http://127.0.0.1:8899/index.html');
  await page.waitForTimeout(500);
  const title = await page.title();
  const turn = await page.locator('#turnText').textContent();
  const state = await page.locator('#gameState').textContent();
  const canvas = page.locator('#board');
  const box = await canvas.boundingBox();
  function pt(x, y) {
    const margin = box.width * 0.09;
    const spacing = (box.width - margin * 2) / 8;
    return { x: box.x + margin + x*spacing, y: box.y + margin + y*spacing };
  }
  async function click(ix, iy) {
    const p = pt(ix, iy);
    await page.mouse.click(p.x, p.y);
    await page.waitForTimeout(50);
  }
  // Capture test: black at 4,3; white at 4,4; black 3,4; white elsewhere; black 5,4; white elsewhere; black 4,5 => capture white center.
  await click(4,3);
  await click(0,0);
  await click(3,4);
  await click(0,1);
  await click(5,4);
  await click(0,2);
  await click(4,5);
  const blackScore1 = await page.locator('#blackScore').textContent();
  const whiteScore1 = await page.locator('#whiteScore').textContent();
  const historyCount1 = await page.locator('#historyLog li').count();
  const stoneCount = await page.evaluate(() => {
    const SIZE = 9;
    let count = 0;
    for (let y=0; y<SIZE; y++) for (let x=0; x<SIZE; x++) if (window.board?.[y]?.[x]) count++;
    return count;
  }).catch(()=>null);
  // Try suicide: white to move? after 7 moves black just played, white to move. Surround center already black? The attempted white move at 4,4 should be suicide.
  const turnBeforeSuicide = await page.locator('#turnText').textContent();
  const historyBeforeSuicide = await page.locator('#historyLog li').count();
  await click(4,4);
  const historyAfterSuicide = await page.locator('#historyLog li').count();
  const turnAfterSuicide = await page.locator('#turnText').textContent();
  const gameStateAfterSuicide = await page.locator('#gameState').textContent();
  const boardState = await page.evaluate(() => {
    const text = document.querySelector('#historyLog').textContent;
    return text;
  });
  console.log(JSON.stringify({title, turn, state, blackScore1, whiteScore1, historyCount1, turnBeforeSuicide, historyBeforeSuicide, historyAfterSuicide, turnAfterSuicide, gameStateAfterSuicide, errors}, null, 2));
  await browser.close();
})();
